// Junta o diagnóstico do Claude com os KPIs da unidade
const risco = $("Unidades em risco (com dedupe)").all();
const respostas = $input.all();

return respostas.map((r, i) => {
  const kpis = risco[i].json;
  const diagnostico = (r.json.content?.[0]?.text || '').trim()
    || `Unidade ${kpis.unidade_nome} em ${kpis.pct_meta}% da meta com ${kpis.dias_restantes} dias restantes.`;
  return { json: { ...kpis, diagnostico } };
});

